from typing import Setfrom abc import abstractmethodfrom .._private.i_covpy_ebyeaggr import ICoveragePyEbyeAggregatorfrom path_validator import PathValidatorclass _ABaseCoverageEbyeAggregator(ICoveragePyEbyeAggregator):	"""		Represents a base `ICoveragePyEbyeAggregator`, containing the control logic		common to every `ICoveragePyEbyeAggregator`.                The format of the "coverage.py" report being processed is specified by the        descendants of this abstract class	"""		def __init__(self):		"""			Creates a new _ABaseCoverageEbyeAggregator		"""		self._path_val: PathValidator = PathValidator()		self._excls: Set[str] = set()					def add_exclusion(self, excl_entity: str, pass_onerror: bool = False):		if (excl_entity is None) or (excl_entity == ""):			raise ValueError()		if excl_entity in self._excls:			self._excls.remove(excl_entity)		else:			if not pass_onerror:				raise ValueError()							def rem_exclusion(self, excl_entity: str, pass_onerror: bool = False):		if (excl_entity is None) or (excl_entity == ""):			raise ValueError()		if excl_entity not in self._excls:			self._excls.add(excl_entity)		else:			if not pass_onerror:				raise ValueError()							def aggregate(			self,			report_path: str,			focal_root: str,			aggr_path: str	):		self._assert_paths(report_path, focal_root, aggr_path)		self._ap__assert_report_type(report_path)		self._ap__aggregate_spec(report_path, focal_root, aggr_path, self._excls)					##	============================================================	##						PRIVATE METHODS	##	============================================================			@abstractmethod	def _ap__assert_report_type(self, report_path: str):		"""			Verifies if the report type, at the given path, corresponds to the			type of coverage reports treated by the descendants of this abstract			class.						If the verification has success, this operation is equivalent to a no-op			Into this method is guaranteed:								- That each `report_path` isn't `None` neither is an empty string				- That each `report_path` is an existing and acceptable path							Parameters			----------				report_path: str					A string representing the path to the coverage.py report                    whose type needs to be verified								Raises			------				WrongReportTypeError					Checks whether `report_path` represents a report of a type                    not handled by the subclasses of this abstract class		"""		pass			@abstractmethod	def _ap__aggregate_spec(			self,			report_path: str,			focal_root: str,			aggr_path: str,			exclusions: Set[str]	):		"""			Aggregates the statement coverage data stored in the report at the data path,            converting it into entity-level statement coverage data based on the standalone            code entities (functions or methods) defined in the module files within the            provided Focal Project Root Path.			Any standalone entities selected for exclusion prior to calling this operation			are omitted.			Upon completion of the aggregation, the data is written, in the format described			by the interface contract, to the file at the path `aggr_path`.			The following is guaranteed within this method:							- That no parameter has a value of `None` or is an empty string                - That every parameter is an existing and accessible path							Parameters			----------				report_path: str                    A string representing the path to the coverage.py report to be used									focal_root: str                    A string representing the Focal Project Root Path associated with the report                    provided, where the functions used to aggregate the data are located                                    aggr_path: str					A string representing the path that will contain the aggregated data in the					format described in the interface contract                exclusions: Set[str]                    A set of strings representing the independent entities to be excluded from                    the data aggregation		"""		pass			##	============================================================	##						PRIVATE METHODS	##	============================================================			def _assert_paths(			self,			report_path: str,			focal_root: str,			aggr_path: str	):		"""			Checks whether the provided paths are valid for use in the			`.aggregate(...)` operation.            If the check is successful, this operation is equivalent to a no-op.                        Parameters            ----------				report_path: str                    A string representing the path containing the coverage.py report                    to be used                focal_root: str					A string representing the Focal Project Root Path associated with the report                    provided, where the functions used to aggregate the data are located                aggr_path: str                    A string representing the path that will contain the aggregated data in the format                    described in the interface contract			Raises            ------                ValueError                    Occurs if:                        - The `report_path` parameter is `None` or an empty string                        - The `focal_root` parameter is `None` or an empty string						- The `aggr_path` parameter is `None` or an empty string                        - The `focal_root` parameter represents a non-existent or inaccessible path                        - The `aggr_path` parameter represents a non-existent or inaccessible path		"""		if (			(report_path is None) or (report_path == "") or			(focal_root is None) or (focal_root == "") or			(aggr_path is None) or (aggr_path == "")		):			raise ValueError()				try:			self._path_val.assert_path(report_path)			self._path_val.assert_path(focal_root)			self._path_val.assert_path(aggr_path)		except (			NotADirectoryError, FileNotFoundError,			PermissionError, OSError		):			raise ValueError()